INSERT INTO team_tactic_setups VALUES(1,'2025-26','FC26','optimal','4-2-3-1 Wide','Short Passing','Balanced',52,NULL,'Emery 25/26: positional short build-up from the back (Martínez + Pau Torres BPD) — Short Passing. Defence is a compact 4-4-2 MID-block with opportunistic ball-winning, not an aggressive press or ultra-high line — Balanced, line ~52 (mid). CORRECTION 2026-07-02: previously High/68 from the 23/24 high-line narrative; 25/26-specific analyses (themastermindsite, totalfootballanalysis) and zero counter-goals-conceded contradict it — see tactic_observations scope=defence. Pairs with player_role_map kind=optimal. [2026-07-02 FORMATION PIN: in-game formation fixed to 4-2-3-1 Wide — left attacking slot is LM (WM type), so analysis-label LW prescriptions map to wm_* in-game equivalents and measured-nearest roles were refit vs wm kernels (see transfer_targets LM rows + player_role_map kind=role:LM).]','MEDIUM — team-setting mapping grounded in 25/26 analyses + measured heatmaps, but not yet validated in-game. Validate by building the tactic in FC26, saving tactic_code, comparing in-game vs measured heatmaps.');
INSERT INTO team_tactic_setups VALUES(2,'2025-26','FC26','optimal:rogers10','4-2-3-1 Wide','Short Passing','Balanced',47,NULL,'PERSONNEL VARIANT of kind=optimal for the Rogers-at-No.10 XI (e.g. Baturina/Tavernier LM + Rogers CAM). Two data drivers (2026-07-03 인선-전술 분석, docs/20 규칙 B): (1) front-six normalized defensive share drops 31.0%→28.8% (lowest of all variants) — line lowered 52→47 to compensate; (2) attack flips right (unit lane L 18%→12%, Rogers CAM centroid x=57.5) — LEFT exposure is asymmetric, so pair with LB Attack compensation + RM wm_widemid/Support (rule A-3). Build-up stays Short Passing (deep drop-in creators support it). Counter is a contested/away experiment only.','MEDIUM — same in-game-unvalidated caveat as kind=optimal; validate via tactic_code + in-game heatmap comparison.');
